from flask import Flask, render_template, request, jsonifyimport pandas as pdimport joblibapp = Flask(__name__)#Load modelsMODELS = {    "นายแพทย์": {        "Logistic Regression": joblib.load("exported_model/doctor/logistic.joblib"),        "Decision Tree": joblib.load("exported_model/doctor/decision_tree.joblib"),        "Random Forest": joblib.load("exported_model/doctor/random_forest.joblib"),        "XGBoost": joblib.load("exported_model/doctor/xgboost.joblib"),    },    "พยาบาลวิชาชีพ": {        "Logistic Regression": joblib.load("exported_model/nurse/logistic.joblib"),        "Decision Tree": joblib.load("exported_model/nurse/decision_tree.joblib"),        "Random Forest": joblib.load("exported_model/nurse/random_forest.joblib"),        "XGBoost": joblib.load("exported_model/nurse/xgboost.joblib"),    },    "เภสัชกร": {        "Logistic Regression": joblib.load("exported_model/pharmacist/logistic.joblib"),        "Decision Tree": joblib.load("exported_model/pharmacist/decision_tree.joblib"),        "Random Forest": joblib.load("exported_model/pharmacist/random_forest.joblib"),        "XGBoost": joblib.load("exported_model/pharmacist/xgboost.joblib"),    },    "ทันตแพทย์": {        "Logistic Regression": joblib.load("exported_model/dentist/logistic.joblib"),        "Decision Tree": joblib.load("exported_model/dentist/decision_tree.joblib"),        "Random Forest": joblib.load("exported_model/dentist/random_forest.joblib"),        "XGBoost": joblib.load("exported_model/dentist/xgboost.joblib"),    },}EXCEL_PATH = "ข้อมูลทดสอบ v3.xlsx"SHEETS = [    "แพทย์",    "พยาบาลวิชาชีพ",    "ทันตแพทย์",    "เภสัชกร"]def load_all_sheets(path):    dfs = []    for sheet in SHEETS:        df = pd.read_excel(path, sheet_name=sheet)        df["sheet_job"] = sheet        dfs.append(df)    return pd.concat(dfs, ignore_index=True)def clean_hr_df(df: pd.DataFrame) -> pd.DataFrame:    df = df.copy()    df["health_region"] = pd.to_numeric(df["ตามจ.18เขต"], errors="coerce")    df["salary"] = pd.to_numeric(df["เงินเดือนรวม"], errors="coerce")    df["job_line"] = df["sheet_job"]    df["job_type"] = df["ตามจ.18ประเภทตำแหน่ง"]    df["job_level"] = df["ตามจ.18ระดับตำแหน่ง"]    df["staff_type"] = df["ประเภทบุคลากร"]    df["province"] = df["ตามจ.18จังหวัด"]    df["agency_type"] = df["ตามจ.18ประเภทหน่วยงาน"]    df["status"] = df["สถานะตำแหน่ง"]    df["occupied_flag"] = df["status"].apply(        lambda x: 1 if "มีคนครอง" in str(x) else 0    )    df["gender"] = df["เพศ"]    df["age"] = pd.to_numeric(df["อายุ"], errors="coerce")    df["work_year"] = pd.to_numeric(df["อายุราชการ"], errors="coerce")    df["retire_year"] = pd.to_numeric(        df["ปีที่เหลือก่อนเกษียณ"],        errors="coerce"    ).fillna(-1)    return df.dropna(subset=["health_region", "age"])HR_DF = clean_hr_df(load_all_sheets(EXCEL_PATH))# Build inputdef build_input(form):    age = int(form.get("age"))    work_years = int(form.get("work_years"))    # สมมติอายุเกษียณ 60    years_to_retire = max(60 - age, 0)    df = pd.DataFrame([{        # ===== NUMERIC =====        "เงินเดือนรวม": float(form.get("salary")),        "ตามจ.18เขต": int(form.get("region")),        "อายุ": age,        "อายุราชการ": work_years,        "ปีที่เหลือก่อนเกษียณ": years_to_retire,        # ===== CATEGORICAL =====        "ตามจ.18ประเภทตำแหน่ง": form.get("job_type"),        "ตามจ.18ระดับตำแหน่ง": form.get("job_level"),        "ประเภทบุคลากร": form.get("staff_type"),        "ตามจ.18จังหวัด": form.get("province"),        "ตามจ.18ประเภทหน่วยงาน": form.get("agency_type"),        "เพศ": form.get("gender"),    }])    return df# Routes@app.route("/")def home():    return render_template("home.html")@app.route("/predict", methods=["GET", "POST"])def predict():    result = summary = error = form_data = None    if request.method == "POST":        form_data = request.form        try:            job_line = request.form.get("job_line")            model_name = request.form.get("model")            if job_line not in MODELS:                raise ValueError(f"ไม่พบโมเดลสำหรับ {job_line}")            if model_name not in MODELS[job_line]:                raise ValueError(f"ไม่พบโมเดล {model_name}")            model = MODELS[job_line][model_name]            df = build_input(form_data)            prob = model.predict_proba(df)[0]            leave = round(prob[1] * 100, 2)            stay = round(prob[0] * 100, 2)            risk, color = (                ("ต่ำ", "green") if leave < 30 else                ("ปานกลาง", "yellow") if leave < 60 else                ("สูง", "red")            )            result = {                "leave": leave,                "stay": stay,                "risk": risk,                "color": color,                "model": model_name,                "job": job_line            }            summary = {                "salary": form_data.get("salary"),                "region": form_data.get("region"),                "job_line": job_line,                "job_type": form_data.get("job_type"),                "job_level": form_data.get("job_level"),                "staff_type": form_data.get("staff_type"),                "province": form_data.get("province"),                "agency_type": form_data.get("agency_type"),            }        except Exception as e:            error = str(e)    return render_template(        "predict.html",        result=result,        summary=summary,        error=error,        form_data=form_data    )@app.route("/dashboard")def dashboard():    job_counts = HR_DF.groupby("job_line").size().to_dict()    return render_template(        "dashboard.html",        job_counts=job_counts    )@app.route("/api/dashboard")def dashboard_api():    df = HR_DF.copy()    region = request.args.get("region")    province = request.args.get("province")    jobs = request.args.get("job")    status = request.args.get("status")    if region and region.isdigit():        df = df[df["health_region"] == int(region)]    if province:        df = df[df["province"] == province]    if jobs:        df = df[df["job_line"].isin(jobs.split(","))]    if status == "occupied":        df = df[df["occupied_flag"] == 1]    elif status == "vacant":        df = df[df["occupied_flag"] == 0]    def vc(series):        return (            series.dropna()            .astype(str)            .value_counts()            .sort_index()            .to_dict()        )    # ===== STATUS =====    occupied = df["occupied_flag"].sum()    vacant = (df["occupied_flag"] == 0).sum()    # ===== AGE GROUP =====    df["age_group"] = pd.cut(        df["age"],        bins=[0,29,39,49,59,200],        labels=["<30 ปี","30-39 ปี","40-49 ปี","50-59 ปี","60+ ปี"]    )    # ===== RETIRE GROUP =====    df["retire_group"] = pd.cut(        df["retire_year"],        bins=[-1,5,10,20,100],        labels=["0-5 ปี","6-10 ปี","11-20 ปี","20+ ปี"]    )    allowed_job_levels = [        "ปฏิบัติการ",        "ชำนาญการ",        "ชำนาญการพิเศษ",        "เชี่ยวชาญ",        "ทรงคุณวุฒิ"    ]    df["job_level_filtered"] = df["job_level"].where(        df["job_level"].isin(allowed_job_levels)    )    return jsonify({        "kpi": {            "total": len(df),            "occupied": int((df["occupied_flag"] == 1).sum()),            "vacant": int((df["occupied_flag"] == 0).sum()),            "avg_salary": round(df["salary"].mean(), 2) if len(df) else 0        },        "overview": {            "job": vc(df["job_line"]),            "region": vc(df["health_region"]),            "age": vc(df["age_group"]),            "gender": vc(df["gender"]),            "work_year": vc(df["work_year"].fillna(0).round()),            "retire": vc(df["retire_group"]),            "status": vc(df["status"]),            "job_level": vc(df["job_level_filtered"]),            "agency_type": vc(df["agency_type"]),            "province": vc(df["province"])        },    })@app.route("/api/provinces")def api_provinces():    region = request.args.get("region")    df = HR_DF.copy()    if region:        df = df[df["health_region"] == int(region)]    provinces = sorted(df["province"].dropna().unique())    return jsonify(provinces)@app.route("/contact")def contact():    return render_template("contact.html")if __name__ == "__main__":    app.run(host="0.0.0.0", port=5000)